#!/usr/bin/env node
/**
 * Quantum_Shield v2.0 — Document Generation Suite
 * Generates all 7 professional .docx documents
 *
 * Usage:
 *   cd /path/to/this/folder
 *   npm install docx
 *   node generate_all.js
 *
 * Each document is generated by its own module:
 *   gen_doc001_techspec.js       → DOC-001: Technical Specification
 *   gen_doc002_architecture.js   → DOC-002: Architecture & System Design
 *   gen_doc003_usermanual.js     → DOC-003: User Manual
 *   gen_doc004_itguide.js        → DOC-004: IT Deployment Guide
 *   gen_doc005_productspec.js    → DOC-005: Product Specification
 *   gen_doc006_securityaudit.js  → DOC-006: Security Audit Package
 *   gen_doc007_recovery.js       → DOC-007: Recovery Procedures
 */

const path = require("path");

const generators = [
  { id: "DOC-001", name: "Technical Specification",      mod: "./gen_doc001_techspec" },
  { id: "DOC-002", name: "Architecture & System Design", mod: "./gen_doc002_architecture" },
  { id: "DOC-003", name: "User Manual",                  mod: "./gen_doc003_usermanual" },
  { id: "DOC-004", name: "IT Deployment Guide",          mod: "./gen_doc004_itguide" },
  { id: "DOC-005", name: "Product Specification",        mod: "./gen_doc005_productspec" },
  { id: "DOC-006", name: "Security Audit Package",       mod: "./gen_doc006_securityaudit" },
  { id: "DOC-007", name: "Recovery Procedures",          mod: "./gen_doc007_recovery" },
];

async function main() {
  const outDir = __dirname;

  console.log("");
  console.log("\u2550".repeat(60));
  console.log("  Quantum_Shield v2.0 \u2014 Document Generation Suite");
  console.log("  Generating 7 professional .docx documents...");
  console.log("\u2550".repeat(60));
  console.log("");

  const start = Date.now();

  for (const gen of generators) {
    try {
      const { generate } = require(gen.mod);
      await generate(outDir);
    } catch (err) {
      console.error(`\n  \u2717 FAILED: ${gen.id} (${gen.name})`);
      console.error(`    ${err.message}`);
      if (err.stack) console.error(err.stack.split("\n").slice(1, 4).join("\n"));
      process.exit(1);
    }
  }

  const elapsed = ((Date.now() - start) / 1000).toFixed(1);

  console.log("");
  console.log("\u2550".repeat(60));
  console.log(`  All 7 documents generated successfully! (${elapsed}s)`);
  console.log("\u2550".repeat(60));
  console.log("");
  console.log("  Output files:");
  console.log("    1. USBVault_Enterprise_Technical_Specification_v2.docx");
  console.log("    2. USBVault_Enterprise_Architecture_v2.docx");
  console.log("    3. USBVault_Enterprise_User_Manual.docx");
  console.log("    4. USBVault_Enterprise_IT_Deployment_Guide.docx");
  console.log("    5. USBVault_Enterprise_Product_Specification.docx");
  console.log("    6. USBVault_Enterprise_Security_Audit_Package.docx");
  console.log("    7. USBVault_Enterprise_Recovery_Procedures.docx");
  console.log("");
}

main().catch(err => {
  console.error("Fatal error:", err);
  process.exit(1);
});
